def validate_field_name(field_name: str) -> str:
    """
    Validate and sanitize a field name.
    
    Only allows alphanumeric characters, underscores, and dots for nested fields.
    Blocks access to security-sensitive fields.
    """
    if not isinstance(field_name, str):
        raise FilterValidationError(f"Field name must be a string, got {type(field_name).__name__}")

    if not field_name or len(field_name) > 200:
        raise FilterValidationError("Field name must be between 1 and 200 characters")

    if not SAFE_FIELD_PATTERN.match(field_name):
        raise FilterValidationError(
            f"Invalid field name '{field_name}'. Only alphanumeric characters, "
            "underscores, and dots are allowed."
        )

    # Check against blocked fields (check each part of dotted path)
    parts = field_name.lower().split('.')
    for part in parts:
        if part in BLOCKED_FIELDS:
            raise QuerySecurityError(
                f"Access to field '{field_name}' is not allowed for security reasons."
            )

    # Prevent MongoDB operator injection via field names
    if field_name.startswith('$'):
        raise QuerySecurityError("Field names starting with '$' are not allowed.")

    return field_name


def sanitize_regex_value(pattern: str) -> str:
    """Escape special regex characters in user input to prevent ReDoS."""
    if not isinstance(pattern, str):
        raise FilterValidationError("Regex pattern must be a string")
    if len(pattern) > 500:
        raise FilterValidationError("Regex pattern too long (max 500 characters)")
    return re.escape(pattern)


def validate_value(value: Any, operator: FilterOperator) -> Any:
    """Validate and sanitize a filter value based on the operator."""
    if operator in (FilterOperator.IN, FilterOperator.NOT_IN, FilterOperator.ALL):
        if not isinstance(value, list):
            raise FilterValidationError(f"Operator '{operator.value}' requires a list value")
        if len(value) > 1000:
            raise FilterValidationError("List values cannot exceed 1000 items")
        # Ensure no nested dicts with $ keys (prevents operator injection)
        for item in value:
            _check_no_operator_injection(item)
        return value

    if operator == FilterOperator.BETWEEN:
        if not isinstance(value, (list, tuple)) or len(value) != 2:
            raise FilterValidationError("'between' operator requires a list of exactly 2 values")
        return value

    if operator == FilterOperator.EXISTS:
        if not isinstance(value, bool):
            raise FilterValidationError("'exists' operator requires a boolean value")
        return value

    if operator == FilterOperator.SIZE:
        if not isinstance(value, int) or value < 0:
            raise FilterValidationError("'size' operator requires a non-negative integer")
        return value

    if operator == FilterOperator.TYPE:
        if value not in ALLOWED_BSON_TYPES:
            raise FilterValidationError(f"Invalid BSON type: {value}")
        return value

    if operator in (FilterOperator.REGEX, FilterOperator.CONTAINS,
                    FilterOperator.STARTS_WITH, FilterOperator.ENDS_WITH):
        if not isinstance(value, str):
            raise FilterValidationError(f"Operator '{operator.value}' requires a string value")
        return value

    if operator == FilterOperator.ELEM_MATCH:
        if not isinstance(value, dict):
            raise FilterValidationError("'elem_match' operator requires a dict value")
        return value

    _check_no_operator_injection(value)
    return value


def _check_no_operator_injection(value: Any) -> None:
    """Recursively check that values don't contain MongoDB operator injection."""
    if isinstance(value, dict):
        for key in value:
            if isinstance(key, str) and key.startswith('$'):
                raise QuerySecurityError(
                    f"Operator injection detected: key '{key}' in value is not allowed."
                )
            _check_no_operator_injection(value[key])
    elif isinstance(value, list):
        for item in value:
            _check_no_operator_injection(item)


def build_condition_query(condition: FilterCondition) -> dict:
    """Convert a FilterCondition into a MongoDB query dict."""
    field_name = validate_field_name(condition.field)
    value = validate_value(condition.value, condition.operator)
    op = condition.operator

    if op == FilterOperator.EQUALS:
        return {field_name: {"$eq": value}}
    elif op == FilterOperator.NOT_EQUALS:
        return {field_name: {"$ne": value}}
    elif op == FilterOperator.GREATER_THAN:
        return {field_name: {"$gt": value}}
    elif op == FilterOperator.GREATER_THAN_OR_EQUAL:
        return {field_name: {"$gte": value}}
    elif op == FilterOperator.LESS_THAN:
        return {field_name: {"$lt": value}}
    elif op == FilterOperator.LESS_THAN_OR_EQUAL:
        return {field_name: {"$lte": value}}
    elif op == FilterOperator.IN:
        return {field_name: {"$in": value}}
    elif op == FilterOperator.NOT_IN:
        return {field_name: {"$nin": value}}
    elif op == FilterOperator.EXISTS:
        return {field_name: {"$exists": value}}
    elif op == FilterOperator.REGEX:
        safe_pattern = sanitize_regex_value(value)
        return {field_name: {"$regex": safe_pattern, "$options": "i"}}
    elif op == FilterOperator.CONTAINS:
        safe_pattern = sanitize_regex_value(value)
        return {field_name: {"$regex": safe_pattern, "$options": "i"}}
    elif op == FilterOperator.STARTS_WITH:
        safe_pattern = sanitize_regex_value(value)
        return {field_name: {"$regex": f"^{safe_pattern}", "$options": "i"}}
    elif op == FilterOperator.ENDS_WITH:
        safe_pattern = sanitize_regex_value(value)
        return {field_name: {"$regex": f"{safe_pattern}$", "$options": "i"}}
    elif op == FilterOperator.BETWEEN:
        return {field_name: {"$gte": value[0], "$lte": value[1]}}
    elif op == FilterOperator.SIZE:
        return {field_name: {"$size": value}}
    elif op == FilterOperator.TYPE:
        return {field_name: {"$type": value}}
    elif op == FilterOperator.ALL:
        return {field_name: {"$all": value}}
    elif op == FilterOperator.ELEM_MATCH:
        # For elem_match, we need to recursively validate the sub-conditions
        validated_sub = _validate_elem_match_value(value)
        return {field_name: {"$elemMatch": validated_sub}}
    else:
        raise FilterValidationError(f"Unsupported operator: {op}")


def _validate_elem_match_value(value: dict) -> dict:
    """Validate an $elemMatch sub-document, allowing only safe operators."""
    allowed_operators = {
        "$eq", "$ne", "$gt", "$gte", "$lt", "$lte", "$in", "$nin", "$exists"
    }
    result = {}
    for key, val in value.items():
        if key.startswith('$'):
            if key not in allowed_operators:
                raise QuerySecurityError(
                    f"Operator '{key}' is not allowed in elemMatch conditions."
                )
            _check_no_operator_injection(val)
            result[key] = val
        else:
            # It's a field name within the sub-document
            validate_field_name(key)
            if isinstance(val, dict):
                result[key] = _validate_elem_match_value(val)
            else:
                _check_no_operator_injection(val)
                result[key] = val
    return result


def build_filter_query(filter_group: FilterGroup, depth: int = 0) -> dict:
    """
    Recursively build a MongoDB query from a FilterGroup.
    
    Enforces maximum depth and condition count limits.
    """
    if depth > MAX_QUERY_DEPTH:
        raise FilterValidationError(
            f"Query nesting depth exceeds maximum of {MAX_QUERY_DEPTH}"
        )

    total_conditions = len(filter_group.conditions) + len(filter_group.sub_groups)
    if total_conditions > MAX_FILTER_CONDITIONS:
        raise FilterValidationError(
            f"Too many filter conditions (max {MAX_FILTER_CONDITIONS})"
        )

    query_parts = []

    for condition in filter_group.conditions:
        query_parts.append(build_condition_query(condition))

    for sub_group in filter_group.sub_groups:
        sub_query = build_filter_query(sub_group, depth + 1)
        if sub_query:
            query_parts.append(sub_query)

    if not query_parts:
        return {}

    logical_op = filter_group.logical_operator

    if logical_op == LogicalOperator.AND:
        if len(query_parts) == 1:
            return query_parts[0]
        return {"$and": query_parts}
    elif logical_op == LogicalOperator.OR:
        if len(query_parts) == 1:
            return query_parts[0]
        return {"$or": query_parts}
    elif logical_op == LogicalOperator.NOR:
        return {"$nor": query_parts}
    elif logical_op == LogicalOperator.NOT:
        if len(query_parts) != 1:
            raise FilterValidationError("'not' logical operator requires exactly one condition")
        # $not works at the field level, so we wrap in $nor for top-level negation
        return {"$nor": query_parts}
    else:
        raise FilterValidationError(f"Unsupported logical operator: {logical_op}")


def parse_filter_request(filter_dict: dict) -> FilterGroup:
    """
    Parse a user-provided filter dictionary into a validated FilterGroup.
    
    Expected format:
    {
        "logic": "and" | "or" | "nor",
        "conditions": [
            {"field": "name", "op": "contains", "value": "John"},
            {"field": "age", "op": "gte", "value": 18},
        ],
        "groups": [
            {
                "logic": "or",
                "conditions": [...],
                "groups": [...]
            }
        ]
    }
    """
    if not isinstance(filter_dict, dict):
        raise FilterValidationError("Filter must be a dictionary")

    logic_str = filter_dict.get("logic", "and")
    try:
        logical_op = LogicalOperator(logic_str.lower())
    except (ValueError, AttributeError):
        raise FilterValidationError(
            f"Invalid logical operator '{logic_str}'. "
            f"Allowed: {[op.value for op in LogicalOperator]}"
        )

    group = FilterGroup(logical_operator=logical_op)

    conditions = filter_dict.get("conditions", [])
    if not isinstance(conditions, list):
        raise FilterValidationError("'conditions' must be a list")

    for cond in conditions:
        if not isinstance(cond, dict):
            raise FilterValidationError("Each condition must be a dictionary")

        field_name = cond.get("field")
        op_str = cond.get("op")
        value = cond.get("value")

        if not field_name or not op_str:
            raise FilterValidationError("Each condition must have 'field' and 'op' keys")

        try:
            operator = FilterOperator(op_str.lower())
        except (ValueError, AttributeError):
            raise FilterValidationError(
                f"Invalid operator '{op_str}'. "
                f"Allowed: {[op.value for op in FilterOperator]}"
            )

        group.conditions.append(FilterCondition(
            field=field_name,
            operator=operator,
            value=value,
        ))

    sub_groups = filter_dict.get("groups", [])
    if not isinstance(sub_groups, list):
        raise FilterValidationError("'groups' must be a list")

    for sub_dict in sub_groups:
        group.sub_groups.append(parse_filter_request(sub_dict))

    return group


class SecureFilterService:
    """
    A secure MongoDB filtering service that translates structured filter
    requests into native MongoDB queries without using $where or server-side JS.
    """

    def __init__(
        self,
        connection_string: str,
        database_name: str,
        allowed_collections: Optional[set] = None,
        max_results: int = 1000,
        default_timeout_ms: int = 30000,
    ):
        """
        Initialize the filter service.
        
        Args:
            connection_string: MongoDB connection string.
            database_name: Name of the database to query.
            allowed_collections: Set of collection names that can be queried.
                                 If None, all collections are allowed.
            max_results: Maximum number of results to return.
            default_timeout_ms: Default query timeout in milliseconds.
        """
        self.client = MongoClient(
            connection_string,
            serverSelectionTimeoutMS=5000,
            socketTimeoutMS=default_timeout_ms,
        )
        self.db = self.client[database_name]
        self.allowed_collections = allowed_collections
        self.max_results = max_results
        self.default_timeout_ms = default_timeout_ms

        # Explicitly disable server-side JavaScript execution if possible
        logger.info(
            "SecureFilterService initialized for database '%s'. "
            "Server-side JavaScript ($where) is NOT used.",
            database_name,
        )

    def _get_collection(self, collection_name: str) -> Collection:
        """Get a collection by name, with access control."""
        if not isinstance(collection_name, str) or not SAFE_FIELD_PATTERN.match(collection_name):
            raise QuerySecurityError(f"Invalid collection name: '{collection_name}'")

        if self.allowed_collections is not None:
            if collection_name not in self.allowed_collections:
                raise QuerySecurityError(
                    f"Access to collection '{collection_name}' is not allowed."
                )

        return self.db[collection_name]

    def query(
        self,
        collection_name: str,
        filter_request: dict,
        projection: Optional[dict] = None,
        sort: Optional[list] = None,
        skip: int = 0,
        limit: Optional[int] = None,
    ) -> list:
        """
        Execute a filtered query on a MongoDB collection.
        
        Args:
            collection_name: Name of the collection to query.
            filter_request: Filter specification dict (see parse_filter_request).
            projection: Optional field projection dict.
            sort: Optional list of (field, direction) tuples.
            skip: Number of documents to skip.
            limit: Maximum number of documents to return.
            
        Returns:
            List of matching documents.
        """
        collection = self._get_collection(collection_name)

        # Parse and validate the filter
        filter_group = parse_filter_request(filter_request)
        mongo_query = build_filter_query(filter_group)

        # Validate projection
        safe_projection = self._validate_projection(projection)

        # Validate sort
        safe_sort = self._validate_sort(sort)

        # Enforce limits
        effective_limit = min(limit or self.max_results, self.max_results)
        if skip < 0:
            raise FilterValidationError("Skip must be non-negative")

        logger.info(
            "Executing query on '%s': %s (projection=%s, sort=%s, skip=%d, limit=%d)",
            collection_name, mongo_query, safe_projection, safe_sort, skip, effective_limit,
        )

        try:
            cursor = collection.find(
                filter=mongo_query,
                projection=safe_projection,
                sort=safe_sort,
                skip=skip,
                limit=effective_limit,
            ).max_time_ms(self.default_timeout_ms)

            results = list(cursor)
            logger.info("Query returned %d documents", len(results))
            return results

        except OperationFailure as e:
            logger.error("MongoDB operation failed: %s", e)
            raise
        except PyMongoError as e:
            logger.error("MongoDB error: %s", e)
            raise

    def count(self, collection_name: str, filter_request: dict) -> int:
        """Count documents matching the filter."""
        collection = self._get_collection(collection_name)
        filter_group = parse_filter_request(filter_request)
        mongo_query = build_filter_query(filter_group)

        try:
            return collection.count_documents(
                mongo_query,
                maxTimeMS=self.default_timeout_ms,
            )
        except PyMongoError as e:
            logger.error("MongoDB count error: %s", e)
            raise

    def aggregate(
        self,
        collection_name: str,
        filter_request: dict,
        group_by: Optional[str] = None,
        aggregations: Optional[list] = None,
    ) -> list:
        """
        Perform aggregation queries with filtering.
        
        Args:
            collection_name: Collection to aggregate.
            filter_request: Filter specification.
            group_by: Optional field to group by.
            aggregations: List of aggregation specs, e.g.:
                [{"field": "price", "op": "avg", "alias": "avg_price"}]
        """
        collection = self._get_collection(collection_name)
        filter_group = parse_filter_request(filter_request)
        mongo_query = build_filter_query(filter_group)

        pipeline = []

        # Match stage
        if mongo_query:
            pipeline.append({"$match": mongo_query})

        # Group stage
        if group_by or aggregations:
            group_stage = {"_id": None}

            if group_by:
                validate_field_name(group_by)
                group_stage["_id"] = f"${group_by}"

            allowed_agg_ops = {"sum", "avg", "min", "max", "first", "last", "count"}

            for agg in (aggregations or []):
                if not isinstance(agg, dict):
                    raise FilterValidationError("Each aggregation must be a dictionary")

                agg_field = agg.get("field")
                agg_op = agg.get("op", "").lower()
                alias = agg.get("alias", f"{agg_op}_{agg_field}")

                if agg_op not in allowed_agg_ops:
                    raise FilterValidationError(
                        f"Invalid aggregation operator '{agg_op}'. "
                        f"Allowed: {allowed_agg_ops}"
                    )

                # Validate alias
                if not SAFE_FIELD_PATTERN.match(alias):
                    raise FilterValidationError(f"Invalid alias: '{alias}'")

                if agg_op == "count":
                    group_stage[alias] = {"$sum": 1}
                else:
                    validate_field_name(agg_field)
                    group_stage[alias] = {f"${agg_op}": f"${agg_field}"}

            pipeline.append({"$group": group_stage})

        # Limit results
        pipeline.append({"$limit": self.max_results})

        logger.info("Executing aggregation on '%s': %s", collection_name, pipeline)

        try:
            cursor = collection.aggregate(
                pipeline,
                maxTimeMS=self.default_timeout_ms,
            )
            return list(cursor)
        except PyMongoError as e:
            logger.error("MongoDB aggregation error: %s", e)
            raise

    def _validate_projection(self, projection: Optional[dict]) -> Optional[dict]:
        """Validate field projection."""
        if projection is None:
            return None

        if not isinstance(projection, dict):
            raise FilterValidationError("Projection must be a dictionary")

        safe_projection = {}
        for field_name, include in projection.items():
            validate_field_name(field_name)
            if include not in (0, 1, True, False):
                raise FilterValidationError(
                    f"Projection value for '{field_name}' must be 0 or 1"
                )
            safe_projection[field_name] = int(include)

        return safe_projection

    def _validate_sort(self, sort: Optional[list]) -> Optional[list]:
        """Validate sort specification."""
        if sort is None:
            return None

        if not isinstance(sort, list):
            raise FilterValidationError("Sort must be a list of (field, direction) tuples")

        safe_sort = []
        for item in sort:
            if not isinstance(item, (list, tuple)) or len(item) != 2:
                raise FilterValidationError(
                    "Each sort item must be a (field, direction) pair"
                )
            field_name, direction = item
            validate_field_name(field_name)
            if direction not in (1, -1):
                raise FilterValidationError("Sort direction must be 1 (asc) or -1 (desc)")
            safe_sort.append((field_name, direction))

        return safe_sort

    def close(self):
        """Close the MongoDB connection."""
        self.client.close()
        logger.info("SecureFilterService connection closed.")


